const digest = $json.digest;
const safeJson = JSON.stringify(digest).replace(/'/g, "''");
const sql = `INSERT INTO gda_dashboard_intel_cache (data, created_at) VALUES ('${safeJson}'::jsonb, NOW()) RETURNING id, created_at`;
return [{ json: { sql } }];

const d = $('Pipeline Stats').first().json.digest;
console.log('Pipeline Health Digest generated:', new Date().toISOString());
console.log(`Active: ${d.active_opps} | Pursue: ${d.pursue_count} | Value: $${d.pipeline_value_m}M | Due 7d: ${d.due_7d} | Scored 24h: ${d.scored_24h}`);
return [{ json: { status: 'ok', digest: d } }];
